     8→  
     9→  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    10→
    11→  const { workspaceId } = await req.json();
    12→
    13→  const { data: membership } = await supabase
    14→    .from('workspace_users')
    15→    .select('role')
    16→    .eq('workspace_id', workspaceId)
    17→    .eq('user_id', user.id)
    18→    .single();
    19→
    20→  if (!membership || !['owner', 'admin'].includes(membership.role)) {
    21→    return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
    22→  }
    23→
    24→  const { data: workspace } = await supabase
    25→    .from('workspaces')
    26→    .select('stripe_customer_id')
    27→    .eq('id', workspaceId)
    28→    .single();
    29→
    30→  if (!workspace?.stripe_customer_id) {
    31→    return NextResponse.json({ error: 'No billing account' }, { status: 400 });
    32→  }
    33→
    34→  const session = await stripe.billingPortal.sessions.create({
    35→    customer: workspace.stripe_customer_id,
    36→    return_url: `${process.env.NEXT_PUBLIC_APP_URL}/app/settings/billing`,
    37→  });
    38→
    39→  return NextResponse.json({ url: session.url });
    40→}

